// ── Utils ──────────────────────────────────────────────────────────────────
const todayStr = () => new Date().toISOString().split("T")[0];
const nowStr = () => new Date().toISOString();
const uid = () => Math.random().toString(36).slice(2,9);
const addDays = (d, n) => {
  if (!d) return null;
  const dt = new Date(d); dt.setDate(dt.getDate() + n);
  return dt.toISOString().split("T")[0];
};
const daysUntil = (d) => {
  if (!d) return null;
  return Math.ceil((new Date(d) - new Date()) / 86400000);
};
const fmtDate = (d) => {
  if (!d) return "—";
  return new Date(d + "T12:00:00").toLocaleDateString("en-US", {month:"short",day:"numeric",year:"numeric"});
};
const fmtDateTime = (iso) => {
  if (!iso) return "";
  return new Date(iso).toLocaleString("en-US", {month:"short",day:"numeric",hour:"numeric",minute:"2-digit"});
};
const dobParts = (d) => {
  if (!d) return {mm:"",mmm:"",dd:"",yyyy:"",full:""};
  const dt = new Date(d + "T12:00:00");
  const mm = String(dt.getMonth()+1).padStart(2,"0");
  const dd = String(dt.getDate()).padStart(2,"0");
  const yyyy = String(dt.getFullYear());
  return {mm, mmm: MONTHS_SHORT[dt.getMonth()], dd, yyyy, full: yyyy+mm+dd};
};
const enlistParts = () => {
  const dt = new Date(); dt.setDate(dt.getDate()+10);
  const mm = String(dt.getMonth()+1).padStart(2,"0");
  const dd = String(dt.getDate()).padStart(2,"0");
  const yyyy = String(dt.getFullYear());
  return {mm, mmm: MONTHS_SHORT[dt.getMonth()], mmmm: MONTHS_LONG[dt.getMonth()], dd, yyyy};
};
const up = (s) => (s||"").toUpperCase();
const pad = (s, n) => up(s).padEnd(n);

