const loadStore = async (k) => {
  try { const r = await window.storage.get(k); return r ? JSON.parse(r.value) : []; } catch { return []; }
};
const saveStore = async (k, v) => {
  try { await window.storage.set(k, JSON.stringify(v)); } catch {}
};

