// ── Small components ───────────────────────────────────────────────────────
function ExpiryBadge({label, date}) {
  if (!date) return null;
  const d = daysUntil(date);
  let bg = GREEN;
  if (d <= 0) bg = RED;
  else if (d <= 7) bg = RED;
  else if (d <= 21) bg = AMBER;
  const txt = d <= 0 ? "EXPIRED" : d + "d";
  return (
    <span style={{background:bg,color:"#fff",fontSize:10,padding:"2px 7px",borderRadius:3,fontFamily:"monospace",fontWeight:700,marginLeft:5}}>
      {label}: {txt}
    </span>
  );
}

function StagePill({stage}) {
  const idx = STAGES.indexOf(stage);
  const pct = Math.round((idx / (STAGES.length - 1)) * 100);
  let bg = NAVY_LT;
  if (idx >= STAGES.length - 1) bg = GREEN;
  else if (idx >= 5) bg = GOLD_DIM;
  return (
    <span style={{background:bg,color:GOLD_LT,fontSize:10,padding:"3px 8px",borderRadius:3,fontWeight:700,letterSpacing:"0.04em",whiteSpace:"nowrap"}}>
      {stage} · {pct}%
    </span>
  );
}

function Card({children, style, urgent}) {
  const ref = useRef(null);
  const onMove = (e) => {
    const el = ref.current; if (!el) return;
    const r = el.getBoundingClientRect();
    const x = ((e.clientX - r.left) / r.width - 0.5) * 12;
    const y = ((e.clientY - r.top) / r.height - 0.5) * -12;
    el.style.transform = "perspective(700px) rotateY(" + x + "deg) rotateX(" + y + "deg) translateZ(6px)";
    el.style.boxShadow = (-x*2) + "px " + (y*2) + "px 36px rgba(0,0,0,0.55)";
  };
  const onLeave = () => {
    const el = ref.current; if (!el) return;
    el.style.transform = "perspective(700px) rotateY(0deg) rotateX(0deg) translateZ(0px)";
    el.style.boxShadow = "0 6px 28px rgba(0,0,0,0.45)";
  };
  const base = {
    background: "#1a1a1a",
    border: "1px solid " + (urgent ? RED : "#2e2e2e"),
    borderRadius: 6,
    padding: 20,
    transition: "transform 0.15s, box-shadow 0.15s",
    boxShadow: "0 4px 20px rgba(0,0,0,0.5)",
  };
  return (
    <div ref={ref} onMouseMove={onMove} onMouseLeave={onLeave} style={Object.assign({}, base, style)}>
      {children}
    </div>
  );
}

function Sec({title, children}) {
  return (
    <div style={{background:"#1a1a1a",border:"1px solid #2e2e2e",borderLeft:"3px solid "+GOLD,borderRadius:6,padding:"20px 22px",marginBottom:16}}>
      <div style={{fontWeight:700,color:GOLD,marginBottom:16,fontSize:11,letterSpacing:"0.12em"}}>{title.toUpperCase()}</div>
      {children}
    </div>
  );
}

function Row({children}) {
  const cols = Array.isArray(children) ? children.filter(Boolean).length : 1;
  return (
    <div style={{display:"grid",gridTemplateColumns:"repeat("+cols+",1fr)",gap:10,marginBottom:10}}>
      {children}
    </div>
  );
}

function Field({label, value, onChange, type, placeholder}) {
  return (
    <div>
      <label style={labelSt}>{label}</label>
      <input
        type={type||"text"}
        value={value||""}
        onChange={e => onChange(e.target.value)}
        placeholder={placeholder||""}
        style={inputSt}
      />
    </div>
  );
}

function Sel({label, value, onChange, options}) {
  return (
    <div>
      <label style={labelSt}>{label}</label>
      <select value={value||""} onChange={e => onChange(e.target.value)} style={Object.assign({},inputSt,{cursor:"pointer"})}>
        <option value="">Select...</option>
        {options.map(o => <option key={o} value={o}>{o}</option>)}
      </select>
    </div>
  );
}

function Btn({children, onClick, color, outline, style}) {
  const bg = outline ? "transparent" : (color || GOLD);
  const fg = outline ? (color || GOLD) : (color === RED ? "#fff" : NAVY);
  return (
    <button
      onClick={onClick}
      style={Object.assign({
        background: bg,
        color: fg,
        border: "1px solid " + (color || GOLD),
        padding: "9px 20px",
        borderRadius: 5,
        cursor: "pointer",
        fontFamily: FONT,
        fontWeight: 700,
        fontSize: 13,
        letterSpacing: "0.05em",
      }, style)}
    >
      {children}
    </button>
  );
}

// ── QR Canvas ──────────────────────────────────────────────────────────────
function QRCanvas() {
  const ref = useRef(null);
  useEffect(() => {
    const canvas = ref.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    const S = 220;
    canvas.width = S; canvas.height = S;
    ctx.fillStyle = "#ffffff";
    ctx.fillRect(0, 0, S, S);
    const cell = 8;
    const cells = Math.floor(S / cell);
    const url = window.location.href;
    const hash = (s) => {
      let h = 5381;
      for (let i = 0; i < s.length; i++) h = ((h << 5) + h) + s.charCodeAt(i);
      return Math.abs(h);
    };
    // Finder pattern helper
    const drawFinder = (ox, oy) => {
      for (let r = 0; r < 7; r++) {
        for (let c = 0; c < 7; c++) {
          const outer = r===0||r===6||c===0||c===6;
          const inner = r>=2&&r<=4&&c>=2&&c<=4;
          ctx.fillStyle = (outer||inner) ? "#0b1f3a" : "#ffffff";
          ctx.fillRect((ox+c)*cell,(oy+r)*cell,cell,cell);
        }
      }
    };
    drawFinder(0,0); drawFinder(cells-7,0); drawFinder(0,cells-7);
    // Data cells
    for (let r = 0; r < cells; r++) {
      for (let c = 0; c < cells; c++) {
        const inTL = r<9&&c<9;
        const inTR = r<9&&c>=cells-9;
        const inBL = r>=cells-9&&c<9;
        if (inTL||inTR||inBL) continue;
        if ((hash(url+r+c)) % 3 === 0) {
          ctx.fillStyle = "#0b1f3a";
          ctx.fillRect(c*cell, r*cell, cell, cell);
        }
      }
    }
    // Center star
    ctx.fillStyle = "#c9a84c";
    ctx.fillRect(S/2-18, S/2-18, 36, 36);
    ctx.fillStyle = "#0b1f3a";
    ctx.font = "bold 22px serif";
    ctx.textAlign = "center";
    ctx.textBaseline = "middle";
    ctx.fillText("★", S/2, S/2+1);
  }, []);
  return <canvas id="qr-canvas" ref={ref} style={{display:"block"}} />;
}

