                <button onClick={()=>setView("apply")} style={{background:"transparent",color:GOLD,border:"2px solid "+GOLD,padding:"14px 36px",borderRadius:3,cursor:"pointer",fontFamily:FONT,fontWeight:700,fontSize:14,letterSpacing:"0.08em"}}>APPLY NOW</button>
